export const checkId = 'cors';
export const name = 'CORS Configured';
export const appliesTo = ['deployable', 'server', 'framework'];

// --- Constants ---

const CORS_DEPS = new Set(['cors', '@fastify/cors', 'koa-cors', 'koa2-cors']);

const SERVER_RUNTIME_DEPS = new Set([
  'express', 'fastify', 'koa', 'hapi', '@hapi/hapi', 'restify', 'polka',
  'connect', 'hono', 'micro', 'restana', 'socket.io', 'ws', '@nestjs/core',
  'nitro', 'nitropack', 'firebase-functions', 'aws-lambda', 'serverless-http',
  '@google-cloud/functions-framework', 'deta', '@vercel/node',
  'apollo-server', '@apollo/server', 'graphql-yoga', 'mercurius'
]);

const FRAMEWORK_DEPS = new Set([
  'next', 'nuxt', 'astro', '@sveltejs/kit', 'solid-start', 'qwik-city',
  '@remix-run/dev', '@remix-run/node', '@remix-run/react', 'gatsby',
  'react-router-dom', 'vue-router', 'react', 'vue', 'svelte', 'preact'
]);

const BUILD_TOOLS = new Set([
  'webpack', 'rollup', 'esbuild', 'parcel', 'vite', 'tsup', 'unbuild',
  'microbundle', 'bunchee', 'pkgroll', 'dts-cli', 'turbo'
]);

const CORS_PATTERNS = [
  /require\s*\(\s*['"][^'"]*cors['"]\s*\)/,
  /import\s+.*?['"][^'"]*cors['"]/,
  /from\s+['"][^'"]*cors['"]/,
  /access-control-allow-origin/i,
  /access-control-allow-methods/i,
  /access-control-allow-headers/i,
  /access-control-allow-credentials/i,
  /access-control-expose-headers/i,
  /access-control-max-age/i,
  /access-control-request/i,
  /cors\s*:\s*(true|\{)/i,
  /cors\s*\(/i,
  /enableCors/i,
  /allowedOrigins?/i,
  /allowOrigin/i,
  /corsOrigins?/i,
  /use\s*\(\s*cors/i,
  /register\s*\([^)]*cors/i,
  /corsHandler/i,
  /handleCors/i,
  /withCors/i,
  /setHeader\s*\(\s*['"]Access-Control/i,
  /headers\s*\(\s*\)\s*\{[^}]*access-control/i,
];

const TUTORIAL_RX = /\b(learn|tutorial|example|examples|starter|template|boilerplate|course|guide|workshop|playground|docs|documentation|showcase|demo|sample|cheatsheet)\b/i;

// --- Helpers ---

function basename(p) {
  const i = p.lastIndexOf('/');
  return i >= 0 ? p.slice(i + 1) : p;
}

function unscoped(name) {
  if (!name) return '';
  const idx = name.indexOf('/');
  return name[0] === '@' && idx > 0 ? name.slice(idx + 1) : name;
}

function isTestOrExamplePath(p) {
  return /(^|\/)(test|tests|__tests__|spec|example|examples|fixtures|fixture|mock|mocks|docs|playground|storybook|e2e|cypress|vitest|jest|coverage|\.tmp|\.next|out|dist|build|node_modules)\//i.test(p);
}

function isApiRouteFile(p) {
  if (!/\.(js|ts|jsx|tsx|mjs|cjs)$/.test(p)) return false;
  if (isTestOrExamplePath(p)) return false;
  return /\/(api|pages\/api|app\/api|src\/pages\/api|src\/app\/api|server\/api|functions\/api|supabase\/functions|netlify\/functions|cloudflare\/functions|api\/routes|server\/routes|src\/routes\/api|controllers)\/[^/]+$/.test(p) ||
         /\+server\.(ts|js|mjs|cjs)$/.test(p) ||
         /\+page\.server\.(ts|js|mjs|cjs)$/.test(p);
}

function isServerEntryFile(p) {
  if (!/\.(js|ts|mjs|cjs|jsx|tsx|mts|cts)$/.test(p)) return false;
  if (isTestOrExamplePath(p)) return false;
  const b = basename(p);
  if (/^(server|app|listen|main|worker)\.(js|ts|mjs|cjs|jsx|tsx|mts|cts)$/.test(b)) return true;
  if (/^src\/(server|app|listen|main|worker)\.(js|ts|mjs|cjs|jsx|tsx|mts|cts)$/.test(p)) return true;
  return false;
}

function hasCorsDep(pj) {
  if (!pj) return false;
  const deps = { ...(pj.dependencies || {}), ...(pj.devDependencies || {}), ...(pj.peerDependencies || {}) };
  return Object.keys(deps).some(k => CORS_DEPS.has(k) || CORS_DEPS.has(unscoped(k)) || /\bcors\b/i.test(unscoped(k)));
}

function isTutorialRepo(pj) {
  if (!pj) return false;
  const signals = [pj.name, pj.description, ...(pj.keywords || [])].filter(Boolean);
  return signals.some(s => TUTORIAL_RX.test(s));
}

function isLibraryOrTool(pj, tree) {
  if (!pj) return false;

  const scripts = pj.scripts || {};
  const allDeps = { ...(pj.dependencies || {}), ...(pj.devDependencies || {}), ...(pj.peerDependencies || {}) };
  const depKeys = Object.keys(allDeps);
  const hasServerDep = depKeys.some(k => SERVER_RUNTIME_DEPS.has(k) || SERVER_RUNTIME_DEPS.has(unscoped(k)));

  const isPublished = pj.private !== true && pj.version;
  const hasEntry = !!(pj.main || pj.module || pj.exports || pj.types || pj.typings);
  const hasNoStart = !scripts.start && !scripts.serve && !scripts['start:prod'] && !scripts.preview;

  // Published package with entry point, no start script, no server deps, no API/server files
  if (isPublished && hasEntry && hasNoStart && !hasServerDep) {
    const hasApi = tree.some(isApiRouteFile);
    const hasServerFile = tree.some(isServerEntryFile);
    if (!hasApi && !hasServerFile) return true;
  }

  // Monorepo of libraries/tools: private + workspaces + packages/ + no apps/services + no start
  if (pj.private === true && pj.workspaces) {
    const hasPackages = tree.some(p => /^packages\/[^/]+\//.test(p));
    const hasApps = tree.some(p => /^(apps|services|sites|clients|workspaces)\/[^/]+\//.test(p));
    if (hasPackages && !hasApps && !scripts.start && !scripts.serve) {
      return true;
    }
  }

  // Keywords strongly indicate library/tool
  const keywords = (pj.keywords || []).map(k => k.toLowerCase());
  const libKeywords = new Set(['library', 'framework', 'plugin', 'sdk', 'toolkit', 'cli', 'command-line', 'bundler', 'compiler', 'build-tool', 'module', 'tool', 'utilities', 'utils', 'helper', 'middleware']);
  if (keywords.some(k => libKeywords.has(k))) {
    if (hasNoStart && !hasServerDep) {
      const hasApi = tree.some(isApiRouteFile);
      if (!hasApi) return true;
    }
  }

  // Build tool with published entry, build scripts, no runtime
  const hasBuildTool = depKeys.some(k => BUILD_TOOLS.has(unscoped(k)));
  if (isPublished && hasEntry && hasNoStart && hasBuildTool && !hasServerDep) {
    const hasApi = tree.some(isApiRouteFile);
    if (!hasApi) return true;
  }

  return false;
}

function analyzeContext(pj, tree) {
  const scripts = pj?.scripts || {};
  const prodDeps = pj?.dependencies || {};
  const allDeps = { ...(pj?.dependencies || {}), ...(pj?.devDependencies || {}) };

  const hasServerDepProd = Object.keys(prodDeps).some(k => SERVER_RUNTIME_DEPS.has(k) || SERVER_RUNTIME_DEPS.has(unscoped(k)));
  const hasServerDepDev = Object.keys(allDeps).some(k => SERVER_RUNTIME_DEPS.has(k) || SERVER_RUNTIME_DEPS.has(unscoped(k)));
  const hasFramework = Object.keys(allDeps).some(k => FRAMEWORK_DEPS.has(k) || FRAMEWORK_DEPS.has(unscoped(k)));
  const hasStartScript = !!(scripts.start || scripts.serve || scripts['start:prod']);
  const hasDevScript = !!(scripts.dev && /\b(serve|server|start|dev)\b/.test(scripts.dev));

  let hasApiRoutes = false;
  let hasServerFile = false;
  let hasClientFiles = false;

  for (const p of tree) {
    if (/(^|\/)node_modules\//.test(p)) continue;
    if (isApiRouteFile(p)) hasApiRoutes = true;
    if (isServerEntryFile(p)) hasServerFile = true;
    if (/\.(jsx|tsx|vue|svelte|html|css|scss|astro)$/.test(p)) hasClientFiles = true;
  }

  return {
    hasServerDepProd,
    hasServerDepDev,
    hasFramework,
    hasStartScript,
    hasDevScript,
    hasApiRoutes,
    hasServerFile,
    hasClientFiles
  };
}

async function findMonorepoCors(files, tree) {
  const isMonorepo = tree.some(p => /(^|\/)pnpm-workspace\.yaml$/.test(p) || /(^|\/)turbo\.json$/.test(p));
  const subPkgs = tree.filter(p => /(^|\/)package\.json$/.test(p) && !/node_modules/.test(p));

  if (!isMonorepo && subPkgs.length <= 1) return null;

  for (const pkgPath of subPkgs.slice(0, 30)) {
    if (pkgPath === 'package.json') continue;
    const content = await files.get(pkgPath);
    if (!content) continue;
    try {
      const subPkg = JSON.parse(content);
      const subDeps = { ...(subPkg.dependencies || {}), ...(subPkg.devDependencies || {}) };
      if (Object.keys(subDeps).some(k => CORS_DEPS.has(k) || CORS_DEPS.has(unscoped(k)) || /\bcors\b/i.test(unscoped(k)))) {
        return pkgPath;
      }
    } catch {
      // skip invalid JSON
    }
  }
  return null;
}

async function scanFilesForCors(files, tree) {
  const candidates = [];

  for (const p of tree) {
    if (!/\.(js|ts|mjs|cjs|jsx|tsx|mts|cts)$/.test(p)) continue;
    if (/(^|\/)node_modules\//.test(p)) continue;
    if (isTestOrExamplePath(p)) continue;

    let score = 0;
    const b = basename(p);

    if (/\.config\.(js|ts|mjs|cjs)$/.test(b)) score += 100;
    if (/^(server|app|listen|main|worker)\.(js|ts|mjs|cjs|jsx|tsx|mts|cts)$/.test(b)) score += 90;
    if (/^src\/(server|app|listen|main|worker)\.(js|ts|mjs|cjs|jsx|tsx|mts|cts)$/.test(p)) score += 85;
    if (isApiRouteFile(p)) score += 80;
    if (/\.route\.(js|ts|mjs|cjs|jsx|tsx|mts|cts)$/.test(p)) score += 70;
    if (/middleware\.(js|ts|mjs|cjs)$/.test(b)) score += 60;
    if (/^(index|app)\.(js|ts|mjs|cjs|jsx|tsx|mts|cts)$/.test(b)) score += 50;
    if (/^src\/(index|app)\.(js|ts|mjs|cjs|jsx|tsx|mts|cts)$/.test(p)) score += 45;
    if (/handlers?\.(js|ts|mjs|cjs)$/.test(b)) score += 40;

    if (score > 0) candidates.push({ path: p, score });
  }

  candidates.sort((a, b) => b.score - a.score);

  for (const { path: filePath } of candidates.slice(0, 40)) {
    const content = await files.get(filePath);
    if (!content) continue;

    for (const pattern of CORS_PATTERNS) {
      if (pattern.test(content)) return filePath;
    }

    if (/\.config\.(js|ts|mjs|cjs)$/.test(filePath)) {
      if (/headers/i.test(content) && /access-control/i.test(content)) return filePath;
    }
  }

  return null;
}

// --- Result builders ---

const na = (msg) => ({ checkId, status: 'not-applicable', confidence: 'high', message: msg, findings: [] });
const pass = (msg, findings = []) => ({ checkId, status: 'pass', confidence: 'high', message: msg, findings });
const fail = (msg, findings = []) => ({ checkId, status: 'fail', confidence: 'medium', message: msg, findings });
const checkit = (msg, findings = []) => ({ checkId, status: 'check-it', confidence: 'low', message: msg, findings });

// --- Main check ---

export async function check(context) {
  const { tree, files, packageJson, repoType } = context;

  try {
    if (!tree || tree.length === 0 || repoType === 'empty') {
      return na('Empty repository');
    }

    if (isTutorialRepo(packageJson)) {
      return na('Tutorial or example repository — CORS not applicable');
    }

    if (isLibraryOrTool(packageJson, tree)) {
      return na('Library, framework, or tool source — CORS not applicable');
    }

    if (hasCorsDep(packageJson)) {
      return pass('CORS dependency found in package.json');
    }

    const subPkgCors = await findMonorepoCors(files, tree);
    if (subPkgCors) {
      return pass(`CORS dependency found in ${subPkgCors}`, [{ file: subPkgCors, issue: 'CORS dependency detected' }]);
    }

    const corsFile = await scanFilesForCors(files, tree);
    if (corsFile) {
      return pass(`CORS configuration found in ${corsFile}`, [{ file: corsFile, issue: 'CORS detected' }]);
    }

    const ctx = analyzeContext(packageJson, tree);

    // Static / frontend-only site without API endpoints
    if (!ctx.hasServerDepProd && !ctx.hasApiRoutes && !ctx.hasServerFile) {
      if (ctx.hasClientFiles || ctx.hasFramework) {
        return na('Static or frontend-only site without API endpoints');
      }
      const hasCode = tree.some(p => /\.(js|ts|jsx|tsx|mjs|cjs)$/.test(p));
      if (!hasCode) return na('No server-side code detected');
    }

    // No server signals at all
    if (!ctx.hasServerDepProd && !ctx.hasServerDepDev && !ctx.hasApiRoutes && !ctx.hasServerFile && !ctx.hasStartScript) {
      return na('No server runtime or API endpoints detected');
    }

    // Server or API context present but no CORS found
    if (ctx.hasServerDepProd || ctx.hasApiRoutes || ctx.hasServerFile || ctx.hasStartScript) {
      return fail('Server or API endpoints detected, but no CORS configuration found', [{ file: 'unknown', issue: 'Missing CORS configuration' }]);
    }

    // Fallback only for genuinely ambiguous cases
    return checkit('Unable to determine CORS requirement from repository structure', [{ file: 'unknown', issue: 'Ambiguous repository structure' }]);
  } catch (err) {
    console.error(`[${checkId}] Unexpected error:`, err);
    return checkit(`Error during CORS check: ${err.message}`, [{ file: 'unknown', issue: `Error: ${err.message}` }]);
  }
}
